CREATE TABLE cars_catalog.gold.factsales ( Revenue DECIMAL(18,2), Units_Sold INT, Revenue_per_unit INT, dim_branch_key BIGINT, dim_dealer_key BIGINT, dim_date_key BIGINT, dim_model_key BIGINT) USING delta COLLATION 'UTF8_BINARY' LOCATION 'abfss://gold@newcarstoragebykishor.dfs.core.windows.net/factsales' TBLPROPERTIES ( 'delta.enableDeletionVectors' = 'true', 'delta.feature.appendOnly' = 'supported', 'delta.feature.deletionVectors' = 'supported', 'delta.feature.invariants' = 'supported', 'delta.minReaderVersion' = '3', 'delta.minWriterVersion' = '7')
